const ZHX_HAN_RE = /[гҗҖ-д¶ҝдёҖ-йҝҝпӨҖ-п«ҝ]/;
const ZHX_HAN_RUN = /[гҗҖ-д¶ҝдёҖ-йҝҝпӨҖ-п«ҝ]+/g;

const ZHX_TONE_MARKS = {
  a: 'ДҒГЎЗҺГ ', e: 'Д“Г©ДӣГЁ', i: 'Д«ГӯЗҗГ¬', o: 'ЕҚГіЗ’ГІ', u: 'Е«ГәЗ”Г№', 'Гј': 'З–ЗҳЗҡЗң',
  A: 'ДҖГҒЗҚГҖ', E: 'Д’ГүДҡГҲ', I: 'ДӘГҚЗҸГҢ', O: 'ЕҢГ“З‘Г’', U: 'ЕӘГҡЗ“Гҷ', 'Гң': 'З•З—ЗҷЗӣ',
};

function zhxAccentSyllable(syl) {
  const m = syl.match(/^([A-Za-zГј:]+)([1-5])$/);
  if (!m) return syl.replace(/u:/g, 'Гј').replace(/U:/g, 'Гң');
  let [, body, tone] = m;
  body = body.replace(/u:/g, 'Гј').replace(/U:/g, 'Гң');
  tone = Number(tone);
  if (tone === 5) return body;
  const lower = body.toLowerCase();
  let idx = lower.indexOf('a');
  if (idx < 0) idx = lower.indexOf('e');
  if (idx < 0) idx = lower.indexOf('ou');
  if (idx < 0) {
    for (let i = lower.length - 1; i >= 0; i--) {
      if ('iouГј'.includes(lower[i])) { idx = i; break; }
    }
  }
  if (idx < 0) return body;
  const marked = ZHX_TONE_MARKS[body[idx]];
  if (!marked) return body;
  return body.slice(0, idx) + marked[tone - 1] + body.slice(idx + 1);
}

function zhxAccent(pinyin) {
  return pinyin.split(' ').map(zhxAccentSyllable).join(' ');
}

// дёҖ/дёҚ tone sandhi (display-only, the first pronunciation rule beginners learn):
// дёҚ bГ№ вҶ’ bГә before a 4th tone; дёҖ yД« вҶ’ yГӯ before 4th, вҶ’ yГ¬ before 1st/2nd/3rd.
// Only applies when a following syllable exists (so ordinals з¬¬дёҖ and final з»ҹдёҖ stay yД«).
function zhxSandhi(numbered) {
  const syls = numbered.split(' ');
  const toneOf = (s) => (s.match(/([1-5])(?:[a-z])?$/i) || [])[1];
  for (let i = 0; i < syls.length - 1; i++) {
    const m = syls[i].match(/^([a-zГј:]+?)([1-5])$/i);
    if (!m) continue;
    const base = m[1].toLowerCase();
    const nt = toneOf(syls[i + 1]);
    if (!nt) continue;
    if (base === 'bu' && m[2] === '4' && nt === '4') syls[i] = m[1] + '2';
    else if (base === 'yi' && m[2] === '1') {
      if (nt === '4') syls[i] = m[1] + '2';
      else if (nt === '1' || nt === '2' || nt === '3') syls[i] = m[1] + '4';
    }
  }
  return syls.join(' ');
}

// CEDICT stores erhua as a separate "r5" syllable; fuse the trailing r onto the
// previous syllable so дёҖзӮ№е„ҝ reads "yГ¬ diЗҺnr", not "yГ¬ diЗҺn r".
function zhxMandarin(numbered) {
  return zhxAccent(zhxSandhi(numbered)).replace(/ r(?=\s|$)/g, 'r');
}

let zhxIndex = null;
let zhxMaxLen = 1;
let zhxDictPromise = null;
let zhxHsk = null;
let zhxSentPromise = null;
let zhxReadings = {};

const ZHX_READING_SLOT = { yue: 0, nan: 1, teo: 2 };

function zhxReadingFor(mode, numberedPinyin, ...wordForms) {
  const fallback = numberedPinyin ? zhxMandarin(numberedPinyin) : null;
  const slot = ZHX_READING_SLOT[mode];
  if (slot === undefined) return fallback;
  for (const w of wordForms) {
    const direct = w && zhxReadings[w]?.[slot];
    if (direct) return direct;
  }
  const word = wordForms.find(Boolean);
  if (word && word.length > 1) {
    const parts = [];
    for (const ch of word) {
      const r = zhxReadings[ch]?.[slot];
      if (!r) return fallback;
      parts.push(r.split(/[,;/]/)[0].trim());
    }
    return parts.join(' ');
  }
  return fallback;
}

function zhxEnsureDict() {
  zhxDictPromise ??= (async () => {
    const [res, hskRes, readRes, cantoRes] = await Promise.all([
      fetch(chrome.runtime.getURL('dict/zh/cedict.json')),
      fetch(chrome.runtime.getURL('dict/zh/hsk.json')).catch(() => null),
      fetch(chrome.runtime.getURL('dict/zh/readings.json')).catch(() => null),
      fetch(chrome.runtime.getURL('dict/zh/canto.json')).catch(() => null),
    ]);
    zhxHsk = hskRes && hskRes.ok ? await hskRes.json() : {};
    zhxReadings = readRes && readRes.ok ? await readRes.json() : {};
    const cantoRows = cantoRes && cantoRes.ok ? await cantoRes.json() : [];
    const rows = (await res.json()).concat(cantoRows);
    zhxIndex = new Map();
    const add = (key, entry) => {
      const list = zhxIndex.get(key);
      if (list) list.push(entry); else zhxIndex.set(key, [entry]);
    };
    for (const [s, t, p, d] of rows) {
      const entry = { s, t, p, d };
      add(s, entry);
      if (t !== s) add(t, entry);
      if (s.length > zhxMaxLen) zhxMaxLen = s.length;
    }
    zhxMaxLen = Math.min(zhxMaxLen, 12);
  })();
  return zhxDictPromise;
}

// Most-frequent reading for common polyphones (еӨҡйҹіеӯ—) and a few multi-char words
// that CEDICT lists in a misleading order. Consulted when a word/char has several
// entries and greedy "first entry wins" would pick a rarer reading. Values are
// CEDICT numbered pinyin, lowercased. This can't be context-perfect (single-char
// readings are context-dependent) but the most-frequent reading is the best default.
const ZHX_PRIORITY = {
  иЎҢ: 'xing2', йҮҚ: 'zhong4', иҝҳ: 'hai2', е·®: 'cha4', йғҪ: 'dou1', й•ҝ: 'chang2',
  дёӯ: 'zhong1', ж•ҷ: 'jiao1', еҘҪ: 'hao3', дәҶ: 'le5', зқҖ: 'zhe5', еҫ—: 'de5',
  ең°: 'de5', дјҡ: 'hui4', дёә: 'wei4', иҰҒ: 'yao4', е°‘: 'shao3', еҸ‘: 'fa1',
  еҗ—: 'ma5', е‘ў: 'ne5', еҗ§: 'ba5', е•Ҡ: 'a5', жӣҫ: 'ceng2', еә”: 'ying1',
  жӣҙ: 'geng4', е…ҙ: 'xing4', з©ә: 'kong1', и§ү: 'jue2', еҸӘ: 'zhi3', з§Қ: 'zhong3',
  дёңиҘҝ: 'dong1 xi5', иҠұе„ҝ: 'hua1 r5', еӨ§еӨ«: 'dai4 fu5', дәәе®¶: 'ren2 jia5',
};

// Extract measure words (йҮҸиҜҚ) from CEDICT's "CL:еҖӢ|дёӘ[ge4],дҪҚ[wei4]" gloss lines
// and surface them as a distinct field so the popup can badge them for learners.
function zhxClassifiers(entries) {
  for (const e of entries) {
    for (const d of e.d) {
      const m = d.match(/^CL:(.+)$/);
      if (!m) continue;
      const cls = m[1].split(',').map((c) => {
        const simp = c.split('|').pop();          // prefer simplified after |
        return simp.replace(/\[[^\]]*\]/g, '').trim();
      }).filter(Boolean);
      if (cls.length) return cls;
    }
  }
  return undefined;
}

function zhxPickEntry(word, entries) {
  const pref = ZHX_PRIORITY[word];
  if (pref) {
    const hit = entries.find((e) => e.p.toLowerCase() === pref);
    if (hit) return hit;
  }
  return entries.find((e) => !/^[A-Z]/.test(e.p)) ?? entries[0];
}

// Word families: given a character, the common multi-character words built from it.
// Characters are meaning-atoms in Chinese, so the family around з”ө (з”өиҜқ/з”өи„‘/з”өи§Ҷ)
// is how vocabulary actually clusters. Built lazily once; ranked HSK-first.
let zhxCharWords = null;
const ZHX_HAN_ONLY = /^[гҗҖ-д¶ҝдёҖ-йҝҝгҖ…]+$/;

function zhxBuildCharIndex() {
  if (zhxCharWords) return;
  zhxCharWords = new Map();
  for (const word of zhxIndex.keys()) {
    if (word.length < 2 || word.length > 4 || !ZHX_HAN_ONLY.test(word)) continue;
    for (const ch of new Set(word)) {
      let list = zhxCharWords.get(ch);
      if (!list) { list = []; zhxCharWords.set(ch, list); }
      list.push(word);
    }
  }
}

function zhxFamily(ch, exclude, mode, limit) {
  zhxBuildCharIndex();
  const words = [...new Set(zhxCharWords.get(ch) ?? [])]
    .filter((w) => w !== exclude)
    .sort((a, b) => (zhxHsk[a] ?? 99) - (zhxHsk[b] ?? 99) || a.length - b.length)
    .slice(0, limit ?? 10);
  return words.map((w) => {
    const entry = zhxPickEntry(w, zhxIndex.get(w));
    const gloss = entry.d.find((d) => !/^CL:/.test(d)) ?? entry.d[0] ?? '';
    return { w, p: zhxReadingFor(mode, entry.p, w, entry.s, entry.t), g: gloss, h: zhxHsk[w] ?? 0 };
  });
}

function zhxSegmentRun(run, mode) {
  const tokens = [];
  let i = 0;
  while (i < run.length) {
    let word = null;
    for (let len = Math.min(zhxMaxLen, run.length - i); len >= 1; len--) {
      const cand = run.slice(i, i + len);
      if (zhxIndex.has(cand)) { word = cand; break; }
    }
    if (!word) {
      tokens.push({ w: run[i], p: zhxReadingFor(mode, null, run[i]), han: true, h: zhxHsk[run[i]] ?? 0 });
      i += 1;
    } else {
      const entries = zhxIndex.get(word);
      const entry = zhxPickEntry(word, entries);
      tokens.push({ w: word, p: zhxReadingFor(mode, entry.p, word, entry.s, entry.t), han: true, h: zhxHsk[word] ?? 0 });
      i += word.length;
    }
  }
  return tokens;
}

function zhxTokenize(text, mode) {
  const tokens = [];
  let last = 0;
  for (const m of text.matchAll(ZHX_HAN_RUN)) {
    if (m.index > last) tokens.push({ w: text.slice(last, m.index), p: null, han: false });
    tokens.push(...zhxSegmentRun(m[0], mode));
    last = m.index + m[0].length;
  }
  if (last < text.length) tokens.push({ w: text.slice(last), p: null, han: false });
  return tokens;
}

function zhxCharBreakdown(word, wordPinyin, mode) {
  const syls = wordPinyin ? wordPinyin.split(' ') : [];
  return [...word].map((ch, i) => {
    const entries = zhxIndex.get(ch);
    if (!entries) return { ch, p: zhxReadingFor(mode, null, ch), gloss: null };
    const target = syls[i] ? syls[i].toLowerCase() : null;
    const candidates = target ? entries.filter((e) => e.p.toLowerCase() === target) : [];
    const match = candidates.find((e) => !/^[A-Z]/.test(e.p))
      ?? candidates[0]
      ?? entries.find((e) => !/^[A-Z]/.test(e.p))
      ?? entries[0];
    const gloss = match.d.find((def) => !/^variant of|^see |^surname /i.test(def)) ?? match.d[0];
    return { ch, p: zhxReadingFor(mode, match.p, ch), gloss };
  });
}

